('safe_supplements', '{"vitamin_d":{"name":"Vitamin D3","dose":"1000-2000 IU/day (safe starting dose)","timing":"With largest meal","duration":"Until lab results","foodSources":["Fatty fish","Egg yolks","Liver","Fortified dairy"],"foodEmojis":["🐟","🥚","🫀","🥛"],"warning":"Do not exceed 4000 IU without lab test. Get tested within 1 month."},"vitamin_b12":{"name":"Vitamin B12","dose":"500-1000 mcg/day (sublingual)","timing":"Morning, empty stomach","duration":"Until lab results","foodSources":["Liver","Red meat","Eggs","Dairy","Fish"],"foodEmojis":["🫀","🥩","🥚","🥛","🐟"],"warning":"Severe deficiency needs injections - lab test required first."},"iron":{"name":"Iron (Ferrous Bisglycinate)","dose":"18 mg/day (women), 8 mg/day (men)","timing":"With Vitamin C, before meals","duration":"Max 3 months without test","foodSources":["Liver","Red meat","Fava beans","Lentils","Spinach"],"foodEmojis":["🫀","🥩","🫘","🌿","🥬"],"warning":"DO NOT take without ferritin test - excess iron is dangerous."},"magnesium":{"name":"Magnesium Glycinate","dose":"200-300 mg/day","timing":"Before bed","duration":"Long-term safe","foodSources":["Almonds","Tahini","Lentils","Fava beans","Bananas","Spinach"],"foodEmojis":["🌰","🫙","🌿","🫘","🍌","🥬"],"warning":"Start with 150 mg - may cause loose stools at high doses."},"omega3":{"name":"Omega-3 (Fish Oil)","dose":"1000 mg EPA+DHA/day","timing":"With fatty meal","duration":"Long-term safe","foodSources":["Salmon","Sardines","Tuna","Walnuts","Flaxseed"],"foodEmojis":["🐟","🐟","🥫","🌰","🌿"],"warning":"Consult doctor if on blood thinners."},"zinc":{"name":"Zinc Picolinate","dose":"15-25 mg/day","timing":"With food","duration":"Max 3 months","foodSources":["Red meat","Liver","Pumpkin seeds","Eggs","Chickpeas"],"foodEmojis":["🥩","🫀","🌻","🥚","🫘"],"warning":"Do not exceed 40 mg/day - can cause copper deficiency."},"vitamin_c":{"name":"Vitamin C","dose":"500-1000 mg/day","timing":"With meals","duration":"Long-term safe","foodSources":["Guava","Orange","Bell pepper","Lemon","Strawberry","Kiwi"],"foodEmojis":["🍐","🍊","🫑","🍋","🍓","🥝"],"warning":"High doses may cause diarrhea and kidney stones."}}'::jsonb),
